import{_ as a,o as i,c as l,a2 as t}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"订单状态与常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"gtpay/faq.md","filePath":"gtpay/faq.md","lastUpdated":1784433066000}'),o={name:"gtpay/faq.md"};function d(c,e,s,p,n,r){return i(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="订单状态与常见问题" tabindex="-1">订单状态与常见问题 <a class="header-anchor" href="#订单状态与常见问题" aria-label="Permalink to &quot;订单状态与常见问题&quot;">​</a></h1><h2 id="订单状态" tabindex="-1">订单状态 <a class="header-anchor" href="#订单状态" aria-label="Permalink to &quot;订单状态&quot;">​</a></h2><table tabindex="0"><thead><tr><th>状态</th><th>说明</th></tr></thead><tbody><tr><td><code>CREATED</code></td><td>已在本地创建，正在提交</td></tr><tr><td><code>WAITING_PAYMENT</code></td><td>等待玩家付款</td></tr><tr><td><code>PAID</code></td><td>已确认到账，等待发放</td></tr><tr><td><code>DELIVERY_PENDING</code></td><td>玩家不在线，等待上线发放</td></tr><tr><td><code>DELIVERING</code></td><td>正在执行奖励命令</td></tr><tr><td><code>COMPLETED</code></td><td>奖励已经发放完成</td></tr><tr><td><code>CANCELLED</code></td><td>玩家按 Q、执行 close 或系统取消</td></tr><tr><td><code>EXPIRED</code></td><td>5 分钟内未完成支付</td></tr><tr><td><code>FAILED</code></td><td>创建、地图读取或奖励执行出现异常</td></tr><tr><td><code>DELIVERY_UNKNOWN</code></td><td>发放过程中服务端重启，需要管理员重试</td></tr></tbody></table><p>查询订单：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay status 订单号</span></span></code></pre></div><p>管理员重试发放：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay retry 订单号</span></span></code></pre></div><h2 id="订单-5-分钟后结束" tabindex="-1">订单 5 分钟后结束 <a class="header-anchor" href="#订单-5-分钟后结束" aria-label="Permalink to &quot;订单 5 分钟后结束&quot;">​</a></h2><p>GTPay 的待支付订单有效时间固定为 5 分钟。</p><p>以下情况会结束订单：</p><ul><li>5 分钟内没有到账。</li><li>玩家按 <code>Q</code> 取消。</li><li>玩家执行 <code>/gtpay close</code>。</li><li>本地收款码读取失败。</li><li>地图数据包无法发送。</li><li>系统返回取消、失败或过期。</li></ul><p>结束后的订单不能继续支付，也不会继续占用分币金额。</p><h2 id="游戏内没有二维码" tabindex="-1">游戏内没有二维码 <a class="header-anchor" href="#游戏内没有二维码" aria-label="Permalink to &quot;游戏内没有二维码&quot;">​</a></h2><p>按顺序检查：</p><ol><li><code>config.yml</code> 中 <code>qrcode.display-in-map</code> 是否为 <code>true</code>。</li><li>当前渠道的收款码文件是否存在。</li><li>文件名和 <code>config.yml</code> 是否一致。</li><li>图片是否为 PNG/JPEG，是否小于 4 MB。</li><li>图片是否放在 <code>plugins/GTPay/qrcode/</code>，而不是服务器根目录。</li><li>执行 <code>/gtpay reload</code> 后重新创建订单。</li><li>控制台是否出现地图包错误。</li></ol><p>1.21.x 地图显示失败时，更新 GTPay 模块并重新启动服务端确认。收款码仍然放在本地 <code>qrcode</code> 文件夹，不填写图片 URL。</p><h2 id="按-q-没有取消" tabindex="-1">按 Q 没有取消 <a class="header-anchor" href="#按-q-没有取消" aria-label="Permalink to &quot;按 Q 没有取消&quot;">​</a></h2><p>检查：</p><ol><li>当前手中是否仍然是 GTPay 付款地图。</li><li>订单是否还处于 <code>WAITING_PAYMENT</code>。</li><li>是否有其他插件拦截了丢弃事件。</li><li>使用 <code>/gtpay status 订单号</code> 查看实际状态。</li></ol><p>也可以直接执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay close</span></span></code></pre></div><h2 id="显示金额和输入金额不同" tabindex="-1">显示金额和输入金额不同 <a class="header-anchor" href="#显示金额和输入金额不同" aria-label="Permalink to &quot;显示金额和输入金额不同&quot;">​</a></h2><p>这是正常的分币识别规则。基础金额 10 元可能显示为：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>10.00、10.01、10.02</span></span></code></pre></div><p>只会根据当前仍在等待支付的订单占用最低可用分币。已完成订单不会继续占用。</p><p>如果出现 10.90、1.65 这类不符合规则的金额：</p><ol><li>不要继续支付该订单。</li><li>记录订单号、基础金额、显示金额和创建时间。</li><li>提交订单号和金额信息处理。</li></ol><h2 id="玩家支付后没有发放" tabindex="-1">玩家支付后没有发放 <a class="header-anchor" href="#玩家支付后没有发放" aria-label="Permalink to &quot;玩家支付后没有发放&quot;">​</a></h2><p>执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay status 订单号</span></span></code></pre></div><h3 id="状态为-waiting-payment" tabindex="-1">状态为 WAITING_PAYMENT <a class="header-anchor" href="#状态为-waiting-payment" aria-label="Permalink to &quot;状态为 WAITING_PAYMENT&quot;">​</a></h3><p>监听 App 没有上报到账，检查：</p><ul><li>App 是否显示连接成功。</li><li><code>merchant_id</code> 是否填错。</li><li><code>monitor_key</code> 是否属于当前服务器。</li><li>微信或支付宝通知是否正常显示。</li><li>实际支付渠道是否和订单渠道一致。</li><li>手机是否被系统省电策略停止。</li></ul><h3 id="状态为-paid-或-delivery-pending" tabindex="-1">状态为 PAID 或 DELIVERY_PENDING <a class="header-anchor" href="#状态为-paid-或-delivery-pending" aria-label="Permalink to &quot;状态为 PAID 或 DELIVERY_PENDING&quot;">​</a></h3><p>说明到账已经确认。玩家上线后会自动继续发放；管理员也可以执行：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/gtpay retry 订单号</span></span></code></pre></div><h3 id="状态为-failed" tabindex="-1">状态为 FAILED <a class="header-anchor" href="#状态为-failed" aria-label="Permalink to &quot;状态为 FAILED&quot;">​</a></h3><p>检查 <code>delivery_message</code> 中的命令错误。最常见原因是：</p><ul><li>点券插件命令写错。</li><li>权限插件命令版本不匹配。</li><li>命令参数中包含未替换的变量。</li><li>使用 <code>[player]</code> 或 <code>[op]</code> 命令时玩家已经离线。</li></ul><h2 id="收款码不能扫描" tabindex="-1">收款码不能扫描 <a class="header-anchor" href="#收款码不能扫描" aria-label="Permalink to &quot;收款码不能扫描&quot;">​</a></h2><p>处理方式：</p><ol><li>直接用手机相机或对应支付 App 扫描原始 PNG，确认收款码本身有效。</li><li>使用正方形图片，四周保留白边。</li><li>不要压缩到过低分辨率。</li><li>不要在图片上叠加文字、边框或服务器 Logo。</li><li>确认微信订单使用微信码，支付宝订单使用支付宝码。</li></ol><h2 id="gui-打不开" tabindex="-1">GUI 打不开 <a class="header-anchor" href="#gui-打不开" aria-label="Permalink to &quot;GUI 打不开&quot;">​</a></h2><p>检查：</p><ol><li>文件是否位于 <code>plugins/GTPay/gui/</code>。</li><li>命令中的文件名是否正确。</li><li><code>rows</code> 是否在 1 到 6 之间。</li><li>布局每行是否超过 9 个字符。</li><li><code>icons</code> 字符是否和 <code>layout</code> 一致。</li><li>YAML 是否少了冒号、引号或缩进。</li></ol><h2 id="gui-按钮不显示" tabindex="-1">GUI 按钮不显示 <a class="header-anchor" href="#gui-按钮不显示" aria-label="Permalink to &quot;GUI 按钮不显示&quot;">​</a></h2><p>检查按钮的：</p><ul><li><code>permission</code> 是否配置了玩家没有的权限。</li><li><code>material</code> 是否存在；1.12 请提供 <code>legacy-material</code>。</li><li>礼包 ID 是否存在且已启用。</li><li>GUI 文件是否保存后执行了 <code>/gtpay reload</code>。</li></ul><h2 id="累计赞助金额不对" tabindex="-1">累计赞助金额不对 <a class="header-anchor" href="#累计赞助金额不对" aria-label="Permalink to &quot;累计赞助金额不对&quot;">​</a></h2><p>累计赞助只统计已经确认到账的订单，不统计：</p><ul><li><code>WAITING_PAYMENT</code>。</li><li><code>CANCELLED</code>。</li><li><code>EXPIRED</code>。</li><li><code>FAILED</code>。</li></ul><p>同时检查：</p><ol><li>当前订单类型是否符合 <code>count_topup</code>、<code>count_gifts</code>。</li><li>活动时间和时区是否正确。</li><li>看的是否是正确的方案 ID。</li><li>是否执行了 <code>/gtpay reload</code>。</li></ol><p>分币识别金额不会计入累计赞助。例如输入 10 元、实际支付 10.01 元，累计仍然按 10.00 元计算。</p><h2 id="多个区的累计赞助和排行没有同步" tabindex="-1">多个区的累计赞助和排行没有同步 <a class="header-anchor" href="#多个区的累计赞助和排行没有同步" aria-label="Permalink to &quot;多个区的累计赞助和排行没有同步&quot;">​</a></h2><p>检查每台服务端：</p><ol><li><code>storage.mode</code> 是否都为 <code>mysql</code> 或都为 <code>redis</code>。</li><li>连接地址、数据库、账号和密码是否指向同一个存储。</li><li><code>cluster-id</code> 是否相同；使用 <code>auto</code> 时检查 5 台的 <code>merchant_id</code> 是否相同。</li><li><code>node-id</code> 是否保持 <code>auto</code>，不要手动给 5 台填同一个节点 ID。</li><li>修改存储配置后是否重启了 Minecraft 服务端。</li></ol><p>默认同步间隔为 10 秒。跨服同步的是已完成订单、礼包限制、累计赞助金额、排行和奖励领取记录；待支付订单仍由创建它的服务端负责查询和发放。</p><p>使用 <code>local</code> 存储时不会同步。</p><h2 id="管理页打不开" tabindex="-1">管理页打不开 <a class="header-anchor" href="#管理页打不开" aria-label="Permalink to &quot;管理页打不开&quot;">​</a></h2><ol><li>在控制台执行 <code>gtpay web open</code>。</li><li>使用同一台机器的浏览器打开控制台返回的地址。</li><li>页面地址中的一次性 token 不要手工截断。</li><li>页面长时间未操作后会自动关闭，需要重新执行 <code>gtpay web open</code>。</li><li>端口冲突时修改 <code>config.yml</code> 的 <code>web.port</code>，关闭管理页后重新执行 <code>gtpay web open</code>。</li></ol><h2 id="仍然无法判断问题" tabindex="-1">仍然无法判断问题 <a class="header-anchor" href="#仍然无法判断问题" aria-label="Permalink to &quot;仍然无法判断问题&quot;">​</a></h2><p>提供以下信息给群主或管理员：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Minecraft 版本</span></span>
<span class="line"><span>GTCore 版本</span></span>
<span class="line"><span>GTPay 版本</span></span>
<span class="line"><span>订单号</span></span>
<span class="line"><span>订单状态</span></span>
<span class="line"><span>控制台相关报错</span></span></code></pre></div><p>不要提供：</p><ul><li><code>server_key</code></li><li><code>monitor_key</code></li><li>收款码原图</li><li>机器人私聊截图</li></ul>`,66)])])}const b=a(o,[["render",d]]);export{u as __pageData,b as default};
